import React, { useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { OrderLineDto } from '../../../services/bh/models';
import { DocumentFormHeader } from '../../../components/layout';
import { OrderLinesGrid, useMaterialLinesSelection } from '../../../components/form';
import { CustomerSearchField } from '../../../components/search';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { customerFieldHandlers, loadCustomerDisplay } from '../../../utils/customerField';
import { emptyOrderLine, normalizeOrderLines, orderLinesTotal } from '../../../utils/orderLines';
import df from '../../../styles/documentForm.module.css';

const TraHangBanFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const initFormName = isEdit ? 'edit-sales-return' : 'create-sales-return';
  const { warehouseOptions } = useVoucherInitData(initFormName);
  const whOpts = useMemo(
    () => [{ value: '', label: '— Chọn kho —' }, ...warehouseOptions],
    [warehouseOptions],
  );
  const [returnDate, setReturnDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerId, setCustomerId] = useState('');
  const [customerCode, setCustomerCode] = useState('');
  const [customerName, setCustomerName] = useState('');
  const [warehouseId, setWarehouseId] = useState('');
  const [reason, setReason] = useState('');
  const [lines, setLines] = useState<OrderLineDto[]>([emptyOrderLine()]);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  const customerHandlers = useMemo(
    () => customerFieldHandlers(setCustomerId, setCustomerCode, setCustomerName),
    [],
  );
  const { copyLine, lineRowProps, setSelectedLineIndex } = useMaterialLinesSelection(lines, setLines);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      bhService.getSalesReturn(id)
        .then(async r => {
          if (cancelled) return;
          setReturnDate(r.returnDate.slice(0, 10));
          setCustomerId(r.customerId);
          setWarehouseId(r.warehouseId);
          setReason(r.reason ?? '');
          setLines(r.lines?.length ? r.lines : [emptyOrderLine()]);
          const display = await loadCustomerDisplay(r.customerId, r.customerName);
          if (!cancelled) {
            setCustomerCode(display.code);
            setCustomerName(display.name);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải phiếu trả hàng'), type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const addLine = () => {
    setLines(prev => [...prev, emptyOrderLine()]);
    setSelectedLineIndex(lines.length);
  };

  const removeLine = (idx: number) => {
    setLines(prev => {
      const next = prev.filter((_, i) => i !== idx);
      return next.length ? next : [emptyOrderLine()];
    });
    setSelectedLineIndex(Math.max(0, idx - 1));
  };

  const handleSave = async () => {
    if (!customerId || !warehouseId) {
      dispatchAppToast(dispatch, { message: 'Chọn khách hàng và kho', type: 'error' });
      return;
    }
    const normalized = normalizeOrderLines(lines);
    if (normalized.length === 0) {
      dispatchAppToast(dispatch, { message: 'Thêm ít nhất một dòng hàng', type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (isEdit && id) {
        await bhService.updateSalesReturn(id, { warehouseId, reason, lines: normalized });
        dispatchAppToast(dispatch, { message: 'Cập nhật trả hàng thành công', type: 'success' });
      } else {
        await bhService.createSalesReturn({
          returnDate,
          customerId,
          warehouseId,
          reason,
          lines: normalized,
        });
        dispatchAppToast(dispatch, { message: 'Tạo trả hàng thành công', type: 'success' });
      }
      navigate('/bh/tra-hang');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  const total = orderLinesTotal(lines);

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/bh/tra-hang')}
        title={isNew ? 'Tạo trả hàng' : 'Sửa trả hàng'}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo phiếu"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin trả hàng</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày trả</label>
            <Input type="date" value={returnDate} onChange={e => setReturnDate(e.target.value)} disabled={isEdit} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Khách hàng</label>
            <CustomerSearchField
              customerId={customerId}
              customerCode={customerCode}
              customerName={customerName}
              onSelect={customerHandlers.onSelect}
              onClear={customerHandlers.onClear}
              disabled={isEdit}
              testIdPrefix="tra-hang-customer"
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Kho</label>
            <Select value={warehouseId} onChange={e => setWarehouseId(e.target.value)} options={whOpts} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Lý do</label>
            <Input value={reason} onChange={e => setReason(e.target.value)} />
          </div>
        </div>
      </div>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết hàng trả</h2>
        <OrderLinesGrid
          lines={lines}
          canEdit
          onChange={setLines}
          onAddLine={addLine}
          onCopyLine={copyLine}
          lineRowProps={lineRowProps}
          onRemoveLine={removeLine}
        />
      </div>
      <div className={df.footer}>
        <div className={df.totalBlock}>
          <span className={df.totalLabel}>Tổng cộng:</span>
          <span className={df.totalValue}>{total.toLocaleString('vi-VN')}</span>
        </div>
      </div>
    </div>
  );
};

export default TraHangBanFormPage;
